def process_graph(graph_data):
    # Make a copy of the input graph so we don't modify it
    graph_copy = graph_data.copy()

    # Find the EK_CONTROL_DOMAIN node with name 'ju1.s3.dom'
    control_domain_id = None
    for node_id, attrs in graph_copy.nodes(data=True):
        if attrs.get('name') == 'ju1.s3.dom' and 'EK_CONTROL_DOMAIN' in attrs.get('type', []):
            control_domain_id = node_id
            break

    # If not found return empty result
    if control_domain_id is None:
        result = []
    else:
        # Helper to compute total capacity under a node
        def compute_capacity(start_node):
            stack = [start_node]
            visited = set()
            total = 0
            while stack:
                n = stack.pop()
                if n in visited:
                    continue
                visited.add(n)
                n_attrs = graph_copy.nodes.get(n, {})
                if 'EK_PORT' in n_attrs.get('type', []):
                    total += n_attrs.get('physical_capacity_bps', 0)
                else:
                    for succ in graph_copy.successors(n):
                        # Check edge types that denote containment or control
                        for edge_key in graph_copy[n][succ]:
                            e_type = graph_copy[n][succ][edge_key].get('type')
                            if e_type in ('RK_CONTAINS', 'RK_CONTROL'):
                                stack.append(succ)
            return total

        # Gather child nodes of the control domain via RK_CONTAINS edges
        child_info = []
        for succ in graph_copy.successors(control_domain_id):
            for edge_key in graph_copy[control_domain_id][succ]:
                e_type = graph_copy[control_domain_id][succ][edge_key].get('type')
                if e_type == 'RK_CONTAINS':
                    child_attrs = graph_copy.nodes.get(succ, {})
                    child_name = child_attrs.get('name', str(succ))
                    capacity = compute_capacity(succ)
                    child_info.append((child_name, capacity))

        # Sort by capacity descending, then by name ascending
        result = sorted(child_info, key=lambda x: (-x[1], x[0]))

    # Prepare the output structure
    update_graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)

    return_object = {
        'type': 'list',
        'data': result,
        'updated_graph': update_graph_json
    }

    return return_object

