def process_graph(graph_data):
    # Create a deep copy of the graph to avoid mutating the input
    graph_copy = graph_data.copy()

    # Helper to find node id by its 'name' attribute
    def find_node(name):
        for node_id, attrs in graph_copy.nodes(data=True):
            if attrs.get('name') == name:
                return node_id
        return None

    # 1. Remove the specified port node
    target_port_name = 'ju1.a3.m1.s3c8.p10'
    target_port_id = find_node(target_port_name)
    if target_port_id is not None:
        graph_copy.remove_node(target_port_id)

    # 2. Count remaining EK_PORT nodes under the specified SWITCH
    switch_name = 'ju1.a3.m1.s3c8'
    switch_id = find_node(switch_name)
    port_count = 0

    if switch_id is not None:
        # DFS traversal using stack
        stack = [switch_id]
        while stack:
            current = stack.pop()
            # If current node is a port, count it
            if 'EK_PORT' in graph_copy.nodes[current].get('type', []):
                port_count += 1
                continue  # ports are leaves, no need to explore further

            # Explore successors via RK_CONTAINS edges
            for succ in graph_copy.successors(current):
                edge_data = graph_copy.get_edge_data(current, succ)
                if edge_data and edge_data.get('type') == 'RK_CONTAINS':
                    stack.append(succ)

    # Prepare the output
    graph_json = json_graph.node_link_data(graph_copy)

    return_object = {
        'type': 'text',
        'data': str(port_count),
        'updated_graph': graph_json
    }
    return return_object
